  ('heelevel3-d0d1b9a2-moex-00257', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '有關會計師應客戶要求保管財物之敘述，下列何者錯誤？', '["會計師或會計師所屬事務所如有代客戶保管財物時，應拒絕其審計案件之委任", "會計師應設置專為處理客戶財物之客戶帳戶", "客戶帳戶之收付，除依授權範圍辦理者外，應經客戶同意始得為之。但疑似或涉及洗錢或 資恐行為之事項，會計師應依法規處理", "會計師為客戶保管財物時，基於增加投資報酬，不論存放時間長短，其可主動將其存入可 孳息或收益帳戶"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
